import pickle

class Preference(object):
    def __init__(self, name=None, value=None):
        self._name = name
        self._value = value

    @property
    def name(self):
        return self._name

    @property
    def value(self):
        return self._value


class NestedPreferences(object):
    def __init__(self):
        self.preferences = {}

    def add_preference(self, preference):
        self.preferences[preference.name] = preference

    def get_preference(self, name):
        try:
            return self.preferences[name].value
        except KeyError as e:
            raise PreferenceError('Preference not found')


class PreferencesManager(object):
    def __init__(self):
        self._preferences = NestedPreferences()

    @property
    def preferences(self):
        return self._preferences

    def add_preference(self, preference):
        self.preferences.add_preference(preference)

    def get_preference(self, name):
        try:
            return self.preferences.get_preference(name).value
        except KeyError as e:
            raise PreferenceError('Preference not found')


class PreferenceError(Exception):
    pass


def save_preferences(preferences):
    with open('preferences', 'wb') as f:
        pickle.dump(preferences, f)


def load_preferences():
    try:
        with open('preferences', 'rb') as f:
            return pickle.load(f)
    except IOError as e:
        raise PreferenceError('No preferences found')


if __name__ == '__main__':

    # Create a sample preference object
    pref = Preference('sample1', 50)

    # Create a nested preferences manager and add the sample preference to it
    prefs_manager = PreferencesManager()
